package bead

import (
	"fmt"
	"path/filepath"
	"testing"

	"github.com/stretchr/testify/require"
)

// benchFixtureSize matches the live `.ddx/beads-archive.jsonl` scale at the
// time this benchmark was written (~1100 closed beads + active queue). The
// fixture loader builds a synthesized corpus matching that shape so the
// benchmark is portable across machines and reproducible across runs.
const benchFixtureSize = 1100

// makeBenchBeads synthesizes an n-bead corpus matching the live archive shape:
// ~70% closed; the remaining ~30% open, partitioned across no-deps (ready),
// closed-dep (ready), and open-dep (blocked) so Ready/Blocked exercise both
// the fast-path and the dep-walk.
func makeBenchBeads(n int) []Bead {
	closedCutoff := (n * 7) / 10
	beads := make([]Bead, n)
	for i := 0; i < n; i++ {
		b := Bead{
			ID:       fmt.Sprintf("bench-%04d", i),
			Title:    fmt.Sprintf("bench bead %d", i),
			Priority: i % 5,
		}
		if i < closedCutoff {
			b.Status = StatusClosed
		} else {
			b.Status = StatusOpen
			switch i % 3 {
			case 1:
				// Dep on a closed bead → ready.
				b.Dependencies = []Dependency{{
					IssueID:     b.ID,
					DependsOnID: fmt.Sprintf("bench-%04d", 50),
					Type:        "blocks",
				}}
			case 2:
				// Dep on an open bead → blocked.
				openTarget := closedCutoff + 1
				if openTarget == i {
					openTarget = closedCutoff + 2
				}
				b.Dependencies = []Dependency{{
					IssueID:     b.ID,
					DependsOnID: fmt.Sprintf("bench-%04d", openTarget),
					Type:        "blocks",
				}}
			}
		}
		beads[i] = b
	}
	return beads
}

func newJSONLBenchStore(b *testing.B, beads []Bead) *Store {
	b.Helper()
	dir := filepath.Join(b.TempDir(), ".ddx")
	s := NewStore(dir)
	require.NoError(b, s.Init())
	require.NoError(b, s.WriteAll(beads))
	return s
}

func newAxonBenchStore(b *testing.B, beads []Bead) *Store {
	b.Helper()
	dir := filepath.Join(b.TempDir(), ".ddx")
	s := NewStore(dir)
	s.backend = NewAxonBackend(dir, s.LockWait)
	require.NoError(b, s.Init())
	require.NoError(b, s.WriteAll(beads))
	return s
}

type benchBackendCtor struct {
	name string
	make func(*testing.B, []Bead) *Store
}

func benchBackends() []benchBackendCtor {
	return []benchBackendCtor{
		{name: "jsonl", make: newJSONLBenchStore},
		{name: "axon", make: newAxonBenchStore},
	}
}

func BenchmarkQueueOps_Ready(b *testing.B) {
	beads := makeBenchBeads(benchFixtureSize)
	for _, bk := range benchBackends() {
		bk := bk
		b.Run(bk.name, func(b *testing.B) {
			s := bk.make(b, beads)
			b.ResetTimer()
			for i := 0; i < b.N; i++ {
				if _, err := s.Ready(); err != nil {
					b.Fatal(err)
				}
			}
		})
	}
}

func BenchmarkQueueOps_Blocked(b *testing.B) {
	beads := makeBenchBeads(benchFixtureSize)
	for _, bk := range benchBackends() {
		bk := bk
		b.Run(bk.name, func(b *testing.B) {
			s := bk.make(b, beads)
			b.ResetTimer()
			for i := 0; i < b.N; i++ {
				if _, err := s.Blocked(); err != nil {
					b.Fatal(err)
				}
			}
		})
	}
}

func BenchmarkQueueOps_Show(b *testing.B) {
	beads := makeBenchBeads(benchFixtureSize)
	for _, bk := range benchBackends() {
		bk := bk
		b.Run(bk.name, func(b *testing.B) {
			s := bk.make(b, beads)
			b.ResetTimer()
			for i := 0; i < b.N; i++ {
				id := fmt.Sprintf("bench-%04d", i%benchFixtureSize)
				if _, err := s.Get(id); err != nil {
					b.Fatal(err)
				}
			}
		})
	}
}

package bead

import "io"

// RawBackend is the low-level storage contract — read/write the entire bead
// corpus and serialize concurrent rewrites. JSONLBackend and ExternalBackend
// implement it. Higher-level operations (CRUD, claim, ready/blocked, dep ops,
// events, archive, JSONL interchange) live on the Backend interface below and
// are composed on top of a RawBackend by Store.
type RawBackend interface {
	Init() error
	ReadAll() ([]Bead, error)
	WriteAll(beads []Bead) error
	WithLock(fn func() error) error
}

// Backend is the high-level bead-tracker contract that callers in
// cli/cmd/bead_*.go and the agent loop will eventually program against. It
// covers everything the bead description for ddx-bbdd7564 calls out: CRUD,
// claim, list/ready/blocked, dep ops, events append, archive split, and
// JSONL export/import.
//
// *Store satisfies this interface; the JSONL implementation lives in store.go
// and delegates per-write serialization to the configured RawBackend
// (JSONLBackend by default, ExternalBackend when DDX_BEAD_BACKEND or the
// .ddx/config.yaml beads.backend field selects bd/br).
//
// chaos_test.go and other conformance suites should program against this
// interface so additional backends can be exercised by the same tests.
type Backend interface {
	// Foundational
	Init() error
	ReadAll() ([]Bead, error)

	// CRUD
	Create(b *Bead) error
	Get(id string) (*Bead, error)
	Update(id string, mutate func(*Bead)) error
	Close(id string) error

	// Claim
	Claim(id, assignee string) error
	ClaimWithOptions(id, assignee, session, worktree string) error
	Unclaim(id string) error

	// Query
	List(status, label string, where map[string]string) ([]Bead, error)
	Ready() ([]Bead, error)
	Blocked() ([]Bead, error)

	// Dep ops
	DepAdd(id, depID string) error
	DepRemove(id, depID string) error
	DepTree(rootID string) (string, error)

	// Events
	AppendEvent(id string, event BeadEvent) error
	Events(id string) ([]BeadEvent, error)

	// Archive split
	Archive(policy ArchivePolicy) ([]string, error)
	Migrate() (MigrateStats, error)

	// JSONL interchange
	Import(source, filePath string) (int, error)
	ExportTo(w io.Writer) error
}

// BackendType constants
const (
	BackendJSONL = "jsonl"
	BackendBD    = "bd"
	BackendBR    = "br"
)

const DefaultCollection = "beads"

package bead

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

// BackendAxon selects the axon-backed RawBackend. Per TD-030 D3 the on-disk
// shape splits beads from their events: one row per bead in the
// ddx_beads collection, plus one entity per event in the
// ddx_bead_events collection linked back to its bead via event_of.
//
// The implementation in axon_backend.go is an in-process emulation of the
// axon GraphQL surface. It serializes the two collections to JSONL files
// under <dir>/axon/ and acquires a single directory lock around mutations.
// The wire-protocol path (genqlient against a real axon server, per TD-030
// §"Wire transport") is the GA delivery; this RawBackend keeps the same
// two-collection split and OCC-compatible bead row schema so the wire path
// is a contained refactor.
//
// AC §3 ("Behind a feature flag until ddx-3ec0chaos signs off"): NewStore
// only routes to AxonBackend when the operator opts in via
// DDX_AXON_EXPERIMENTAL=1. With the flag unset, beads.backend=axon falls
// through to the JSONL default and a stderr warning is emitted so the
// misconfiguration is visible without breaking the workspace.
const BackendAxon = "axon"

// AxonExperimentalEnv gates whether the axon backend may be selected. The
// flag is intentionally separate from beads.backend so the chaos-test bead
// (ddx-743bc194) can flip operators to axon machine-by-machine without
// editing every project's config.
const AxonExperimentalEnv = "DDX_AXON_EXPERIMENTAL"

// axonSchemaVersion is written into every persisted entity. Schema upgrades
// are handled lazy-on-read until axon FEAT-017 ships native schema
// migration (per TD-030 v1 policy on schema versioning).
const axonSchemaVersion = 1

// AxonDirName is the per-store axon subdirectory under .ddx that holds the
// two-collection snapshot files and the lock dir.
const AxonDirName = "axon"

// AxonBeadsCollection / AxonEventsCollection are the logical collection names
// from TD-030's schema mapping. They are surfaced as the on-disk filenames so
// inspecting the directory tells the operator which collection an entity
// belongs to.
const (
	AxonBeadsCollection  = "ddx_beads"
	AxonEventsCollection = "ddx_bead_events"
)

// AxonBackend stores the bead corpus in axon's two-collection shape.
//
// On WriteAll the backend splits each bead's inline Extra["events"] into one
// entity per event under ddx_bead_events and persists the bead row (sans
// inline events) under ddx_beads. ReadAll re-merges events back into
// Extra["events"] so the higher-level Store and the chaos suite see the
// uniform inline-events shape they expect.
//
// Beads with Extra[events_attachment] set (post-Close externalisation) are
// persisted with their events array empty in axon's events collection. The
// attachment file remains the canonical source for those events so Store's
// existing read path (eventsForBead) keeps working unchanged.
type AxonBackend struct {
	Dir        string
	BeadsFile  string
	EventsFile string
	LockDir    string
	LockWait   time.Duration
}

// Compile-time check: AxonBackend satisfies RawBackend.
var _ RawBackend = (*AxonBackend)(nil)

// NewAxonBackend constructs an axon-backed RawBackend rooted at dir. dir is
// the .ddx directory for the project; collection files and the lock live
// under <dir>/axon/.
func NewAxonBackend(dir string, lockWait time.Duration) *AxonBackend {
	root := filepath.Join(dir, AxonDirName)
	return &AxonBackend{
		Dir:        root,
		BeadsFile:  filepath.Join(root, AxonBeadsCollection+".jsonl"),
		EventsFile: filepath.Join(root, AxonEventsCollection+".jsonl"),
		LockDir:    filepath.Join(root, ".lock"),
		LockWait:   lockWait,
	}
}

// AxonExperimentalEnabled reports whether the operator has opted in to the
// experimental axon backend via DDX_AXON_EXPERIMENTAL=1. NewStore consults
// this before routing beads.backend=axon to AxonBackend.
func AxonExperimentalEnabled() bool {
	switch strings.ToLower(strings.TrimSpace(os.Getenv(AxonExperimentalEnv))) {
	case "1", "true", "yes", "on":
		return true
	}
	return false
}

func (a *AxonBackend) Init() error {
	if err := os.MkdirAll(a.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: axon init dir: %w", err)
	}
	for _, path := range []string{a.BeadsFile, a.EventsFile} {
		f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY, 0o644)
		if err != nil {
			return fmt.Errorf("bead: axon init %s: %w", path, err)
		}
		if err := f.Close(); err != nil {
			return fmt.Errorf("bead: axon close %s: %w", path, err)
		}
	}
	return nil
}

// ReadAll loads bead rows and event entities from disk and re-merges events
// back into each bead's Extra["events"]. Orphan events (event_of pointing at
// a missing bead, e.g. after a partial-write crash) are silently dropped.
func (a *AxonBackend) ReadAll() ([]Bead, error) {
	beads, err := a.readBeadRows()
	if err != nil {
		return nil, err
	}
	events, err := a.readEventEntities()
	if err != nil {
		return nil, err
	}
	// Index beads by id so we can attach events and drop orphans.
	byID := make(map[string]*Bead, len(beads))
	for i := range beads {
		byID[beads[i].ID] = &beads[i]
	}
	// Group events by bead id, preserving insertion order on disk.
	grouped := make(map[string][]BeadEvent, len(events))
	order := make(map[string]int, len(events))
	for _, ev := range events {
		if _, ok := byID[ev.beadID]; !ok {
			continue // orphan
		}
		grouped[ev.beadID] = append(grouped[ev.beadID], ev.event)
		if _, seen := order[ev.beadID]; !seen {
			order[ev.beadID] = len(order)
		}
	}
	for id, evs := range grouped {
		b := byID[id]
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		// Skip beads whose events have been externalised — the attachment file
		// is the canonical source post-close and inlining stale events would
		// duplicate the history.
		if hasEventsAttachment(b) {
			continue
		}
		b.Extra["events"] = encodeEventsForExtra(evs)
	}
	return beads, nil
}

// WriteAll splits inline events from each bead and persists both collections.
// Writes are serialised at the directory-lock layer (WithLock); this method
// rewrites both files in temp+rename style so a crash mid-write leaves the
// previous snapshot intact rather than producing torn rows.
func (a *AxonBackend) WriteAll(beads []Bead) error {
	if err := os.MkdirAll(a.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: axon mkdir: %w", err)
	}
	sort.Slice(beads, func(i, j int) bool { return beads[i].ID < beads[j].ID })

	var beadsBuf, eventsBuf bytes.Buffer
	for _, b := range beads {
		// Extract and strip inline events for the split.
		var events []BeadEvent
		if b.Extra != nil {
			if raw, ok := b.Extra["events"]; ok {
				events = decodeBeadEvents(raw)
			}
		}
		stripped := beadWithoutInlineEvents(b)
		row, err := axonEncodeBead(stripped)
		if err != nil {
			return fmt.Errorf("bead: axon marshal %s: %w", b.ID, err)
		}
		beadsBuf.Write(row)
		beadsBuf.WriteByte('\n')

		for i, ev := range events {
			data, err := axonEncodeEvent(b.ID, i, ev)
			if err != nil {
				return fmt.Errorf("bead: axon marshal event %s/%d: %w", b.ID, i, err)
			}
			eventsBuf.Write(data)
			eventsBuf.WriteByte('\n')
		}
	}

	// Write events first so a crash between the two writes leaves orphan
	// events (which ReadAll silently drops) rather than a bead row whose
	// events have not landed yet — favouring the safer side of the partial-
	// write window for an audit log.
	if err := writeAtomicFile(a.EventsFile, eventsBuf.Bytes()); err != nil {
		return fmt.Errorf("bead: axon write events: %w", err)
	}
	if err := writeAtomicFile(a.BeadsFile, beadsBuf.Bytes()); err != nil {
		return fmt.Errorf("bead: axon write beads: %w", err)
	}
	return nil
}

func (a *AxonBackend) WithLock(fn func() error) error {
	wait := a.LockWait
	if wait <= 0 {
		wait = 10 * time.Second
	}
	if err := acquireDirLock(a.Dir, a.LockDir, wait); err != nil {
		return err
	}
	defer os.RemoveAll(a.LockDir)
	return fn()
}

// beadWithoutInlineEvents returns a shallow copy of b whose Extra map omits
// the "events" key. The original Extra map is not mutated so callers can
// continue using the in-memory bead value after the split.
func beadWithoutInlineEvents(b Bead) Bead {
	if b.Extra == nil {
		return b
	}
	if _, ok := b.Extra["events"]; !ok {
		return b
	}
	cp := make(map[string]any, len(b.Extra))

package bead

import (
	"fmt"
	"math/rand"
	"strings"
	"sync"
	"testing"
	"unicode"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// newTestBackend returns a Backend rooted at a fresh temp dir. It exists so
// the chaos suite exercises the JSONL backend through the Backend interface
// (per ddx-bbdd7564 AC §5) rather than through *Store directly.
func newTestBackend(t *testing.T) Backend {
	t.Helper()
	return newTestStore(t)
}

// chaosBackend names a backend constructor for the parameterized chaos suite.
// Per ddx-743bc194, every backend-agnostic chaos scenario must run against both
// the JSONL default and the axon backend so a regression in either path fails
// the same suite.
type chaosBackend struct {
	name string
	make func(*testing.T) Backend
}

func chaosBackends() []chaosBackend {
	return []chaosBackend{
		{name: "jsonl", make: func(t *testing.T) Backend { return newTestStore(t) }},
		{name: "axon", make: func(t *testing.T) Backend { return newAxonStore(t) }},
	}
}

// forEachChaosBackend runs fn once per backend as a parallel subtest. The
// subtest receives a fresh Backend, so scenarios stay isolated per backend.
func forEachChaosBackend(t *testing.T, fn func(*testing.T, Backend)) {
	t.Helper()
	for _, bf := range chaosBackends() {
		bf := bf
		t.Run(bf.name, func(t *testing.T) {
			t.Parallel()
			fn(t, bf.make(t))
		})
	}
}

// TestChaos_ConcurrentAppendSafety spawns 10 goroutines each creating 10 beads
// against the same store. Verifies all 100 beads exist, no duplicates, no corruption.
func TestChaos_ConcurrentAppendSafety(t *testing.T) {
	forEachChaosBackend(t, func(t *testing.T, s Backend) {
		const goroutines = 10
		const beadsEach = 10
		const total = goroutines * beadsEach

		var wg sync.WaitGroup
		errCh := make(chan error, total)

		for g := 0; g < goroutines; g++ {
			g := g
			wg.Add(1)
			go func() {
				defer wg.Done()
				for i := 0; i < beadsEach; i++ {
					b := &Bead{Title: fmt.Sprintf("goroutine-%d-bead-%d", g, i)}
					if err := s.Create(b); err != nil {
						errCh <- fmt.Errorf("goroutine %d create %d: %w", g, i, err)
					}
				}
			}()
		}

		wg.Wait()
		close(errCh)

		var errs []error
		for err := range errCh {
			errs = append(errs, err)
		}
		require.Empty(t, errs, "concurrent creates must not error: %v", errs)

		beads, err := s.ReadAll()
		require.NoError(t, err)
		assert.Len(t, beads, total, "all %d beads must be present", total)

		// Check for duplicates
		seen := make(map[string]int)
		for _, b := range beads {
			seen[b.ID]++
		}
		for id, count := range seen {
			assert.Equal(t, 1, count, "bead %s appears %d times (duplicate)", id, count)
		}

		// Check no corruption: every bead must have a valid ID, title, and status
		for _, b := range beads {
			assert.NotEmpty(t, b.ID, "bead ID must not be empty")
			assert.NotEmpty(t, b.Title, "bead title must not be empty")
			assert.Contains(t, []string{StatusOpen, StatusInProgress, StatusClosed}, b.Status,
				"bead %s has invalid status %q", b.ID, b.Status)
		}
	})
}

// TestChaos_AtomicStatusTransitions spawns 5 goroutines each cycling a single
// bead through open→in_progress→closed→open. After all iterations the bead
// must have a valid status and the store must be fully parseable.
func TestChaos_AtomicStatusTransitions(t *testing.T) {
	forEachChaosBackend(t, func(t *testing.T, s Backend) {
		b := &Bead{Title: "status-churn"}
		require.NoError(t, s.Create(b))
		id := b.ID

		const goroutines = 5
		const iterations = 20

		statuses := []string{StatusOpen, StatusInProgress, StatusClosed}
		var wg sync.WaitGroup

		for g := 0; g < goroutines; g++ {
			g := g
			wg.Add(1)
			go func() {
				defer wg.Done()
				for i := 0; i < iterations; i++ {
					next := statuses[(g+i)%len(statuses)]
					// Ignore errors: contention may cause transient failures that are
					// acceptable (e.g. attempting to set a status that is already set).
					// The critical invariant is no corruption.
					_ = s.Update(id, func(bead *Bead) {
						bead.Status = next
					})
				}
			}()
		}

		wg.Wait()

		// Bead must still exist with a valid status
		got, err := s.Get(id)
		require.NoError(t, err, "bead must be readable after concurrent status updates")
		assert.Contains(t, []string{StatusOpen, StatusInProgress, StatusClosed}, got.Status,
			"bead must have a valid status after concurrent updates")

		// Store must be parseable end-to-end
		allBeads, err := s.ReadAll()
		require.NoError(t, err, "store must be parseable after concurrent status transitions")
		assert.NotEmpty(t, allBeads, "store must not be empty after updates")

		// Verify no partial writes: every entry must decode cleanly
		for _, bead := range allBeads {
			assert.NotEmpty(t, bead.ID)
			assert.NotEmpty(t, bead.Title)
		}
	})
}

// TestChaos_ConcurrentCloseAndAppend reproduces the reported bug:
// one goroutine closes a bead while another creates a new bead concurrently.
// Both operations must persist; neither must clobber the other.
func TestChaos_ConcurrentCloseAndAppend(t *testing.T) {
	forEachChaosBackend(t, func(t *testing.T, s Backend) {
		// Pre-create the bead that will be closed
		existing := &Bead{Title: "to-be-closed"}
		require.NoError(t, s.Create(existing))
		closeID := existing.ID

		const rounds = 50

		for round := 0; round < rounds; round++ {
			// Re-open the bead so we can close it again
			require.NoError(t, s.Update(closeID, func(b *Bead) {
				b.Status = StatusOpen
			}))

			newTitle := fmt.Sprintf("new-bead-round-%d", round)
			var newID string

			var wg sync.WaitGroup
			wg.Add(2)

			// Goroutine A: close the existing bead
			go func() {
				defer wg.Done()
				_ = s.Close(closeID)
			}()

			// Goroutine B: create a new bead
			go func() {
				defer wg.Done()
				nb := &Bead{Title: newTitle}
				if err := s.Create(nb); err == nil {
					newID = nb.ID
				}
			}()

			wg.Wait()

			// The new bead must exist
			if newID != "" {
				got, err := s.Get(newID)
				require.NoError(t, err, "round %d: new bead %s must exist", round, newID)
				assert.Equal(t, newTitle, got.Title, "round %d: new bead title must match", round)
			}

			// The closed bead's status must reflect the close (it may have been
			// re-opened by a subsequent round, but within this round, if the close
			// completed first and create ran after, the close must be visible).
			// The critical check: the closed bead must still exist and be parseable.
			closedBead, err := s.Get(closeID)
			require.NoError(t, err, "round %d: closed bead must still exist", round)
			assert.NotEmpty(t, closedBead.ID, "round %d: closed bead ID must not be empty", round)
		}
	})
}

package bead

import (
	"fmt"
	"strings"
	"time"
)

// Bead represents a portable work item with metadata.
// The schema matches bd/br JSONL format for interchange compatibility.
// Unknown fields from external sources are preserved in Extra.
type Bead struct {
	ID        string    `json:"id"`
	Title     string    `json:"title"`
	Status    string    `json:"status"`
	Priority  int       `json:"priority"`
	IssueType string    `json:"issue_type"`
	Owner     string    `json:"owner,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	CreatedBy string    `json:"created_by,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`

	// Optional fields (bd-compatible)
	Labels      []string `json:"labels,omitempty"`
	Parent      string   `json:"parent,omitempty"`
	Description string   `json:"description,omitempty"`
	Acceptance  string   `json:"acceptance,omitempty"`
	Notes       string   `json:"notes,omitempty"`

	// Dependencies use bd-compatible format
	Dependencies []Dependency `json:"dependencies,omitempty"`

	// Extra holds unknown fields for round-trip preservation.
	// Workflow-specific fields (e.g. HELIX spec-id, execution-eligible)
	// are stored here and written back on save.
	Extra map[string]any `json:"-"`
}

// Dependency represents a link between two beads (bd-compatible format).
type Dependency struct {
	IssueID     string `json:"issue_id"`
	DependsOnID string `json:"depends_on_id"`
